/**
 * Helper function to calculate the Greatest Common Divisor (GCD) of two numbers.
 * @param {number} a
 * @param {number} b
 * @returns {number} GCD of a and b.
 */
function gcd(a, b) {
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}

/**
 * Finds the prime factorization of a number.
 * @param {number} n
 * @returns {Map<number, number>} Map where key is prime and value is its exponent.
 */
function primeFactorization(n) {
    const factors = new Map();
    let d = 2;
    let temp = n;
    while (d * d <= temp) {
        while (temp % d === 0) {
            factors.set(d, (factors.get(d) || 0) + 1);
            temp /= d;
        }
        d++;
    }
    if (temp > 1) {
        factors.set(temp, (factors.get(temp) || 0) + 1);
    }
    return factors;
}

/**
 * Main function to solve the problem.
 * @param {number[]} nums The initial array.
 * @param {number} p The target GCD.
 * @param {number[][]} queries The list of update queries.
 * @returns {number} The count of queries that result in a "good subsequence".
 */
function solve(nums, p, queries) {
    const N = nums.length;

    // --- State Variables for tracking A_p and GCD G ---

    // ValueCounts stores the frequency of each value 'a' = nums[i]/p currently in A_p.
    const valueCounts = new Map(); 

    // PrimeCounts[q] stores a map {e: count}, indicating how many elements in A_p
    // have exactly exponent 'e' for prime 'q'.
    const primeCounts = new Map();

    // Tracks the current GCD of all elements in A_p. Initialize to 0 (identity for GCD is complex, 
    // but we handle the empty/single element case explicitly).
    let currentGCD = 0; 

    // Tracks the count of elements currently in A_p.
    let ApSize = 0; 

    // Tracks the count of indices i where nums[i] == p. (Condition 1 check)
    let pCount = 0;

    // --- Initialization ---

    for (let i = 0; i < N; i++) {
        const val = nums[i];
        if (val % p === 0) {
            const a = val / p;

            if (a === 1) {
                pCount++;
            }

            // Add 'a' to the multiset A_p
            addElementToAp(a);
        }
    }

    // --- Update Helper Functions ---

    /**
     * Adds element 'a' to the dynamic set A_p and updates tracking structures.
     * @param {number} a The element to add.
     */
    function addElementToAp(a) {
        ApSize++;

        // Update value frequency
        valueCounts.set(a, (valueCounts.get(a) || 0) + 1);

        // Update PrimeCounts and GCD
        const factors = primeFactorization(a);

        let tempGCD = currentGCD;
        if (currentGCD === 0) tempGCD = a; // If A_p was empty, current GCD becomes 'a'
        else tempGCD = gcd(currentGCD, a);

        currentGCD = tempGCD;

        for (const [q, e] of factors.entries()) {
            if (!primeCounts.has(q)) {
                primeCounts.set(q, new Map());
            }
            const qCounts = primeCounts.get(q);
            qCounts.set(e, (qCounts.get(e) || 0) + 1);
        }
    }

    /**
     * Removes one instance of element 'a' from the dynamic set A_p and updates tracking structures.
     * This must be called only if 'a' is present.
     * @param {number} a The element to remove.
     */
    function removeElementFromAp(a) {
        if (!valueCounts.has(a) || valueCounts.get(a) === 0) return;

        ApSize--;

        // Update value frequency
        valueCounts.set(a, valueCounts.get(a) - 1);
        if (valueCounts.get(a) === 0) {
            valueCounts.delete(a);
        }

        // Update PrimeCounts and GCD
        const factors = primeFactorization(a);

        // 1. Update PrimeCounts
        for (const [q, e] of factors.entries()) {
            const qCounts = primeCounts.get(q);
            const count = qCounts.get(e);
            if (count === 1) {
                qCounts.delete(e);
                // If this was the last instance for this exponent, we need to find the new minimum exponent for q
                if (qCounts.size === 0) {
                    primeCounts.delete(q); // No elements divisible by q anymore
                }
            } else {
                qCounts.set(e, count - 1);
            }
        }

        // 2. Recompute GCD if necessary
        if (ApSize === 0) {
            currentGCD = 0;
        } else if (ApSize === 1) {
            // Find the single remaining element in A_p
            let remainingElement = 0;
            for (const [val, count] of valueCounts) {
                if (count > 0) {
                    remainingElement = val;
                    break;
                }
            }
            currentGCD = remainingElement;
        } else {
            // If ApSize >= 2, we must recompute GCD based on minimum exponents found in PrimeCounts
            let newGCD = 1;

            for (const [q, qCounts] of primeCounts.entries()) {
                // Find the smallest exponent e_min for prime q
                let minE = Infinity;
                for (const e of qCounts.keys()) {
                    minE = Math.min(minE, e);
                }

                // Multiply into newGCD: q ^ minE
                newGCD *= Math.pow(q, minE);
            }
            currentGCD = newGCD;
        }
    }


    // --- Query Processing ---

    let goodSubsequenceCount = 0;

    for (const [ind, newVal] of queries) {
        const oldVal = nums[ind];
        const isOldDivisible = oldVal % p === 0;
        const isNewDivisible = newVal % p === 0;

        // 1. Handle removal if necessary
        if (isOldDivisible) {
            const aOld = oldVal / p;
            removeElementFromAp(aOld);
        }

        // 2. Update nums array and pCount
        nums[ind] = newVal;
        if (newVal === p) {
            pCount++;
        } else if (oldVal === p) {
            pCount--;
        }

        // 3. Handle insertion if necessary
        if (isNewDivisible) {
            const aNew = newVal / p;
            addElementToAp(aNew);
        }

        // --- Check for Good Subsequence ---

        let existsGoodSubsequence = false;

        // Condition 1: Existence of element 'p' itself (Length 1)
        if (pCount > 0) {
            existsGoodSubsequence = true;
        } 
        // Condition 2: Existence of a coprime pair (or GCD=1 if size >= 2)
        else if (ApSize >= 2 && currentGCD === 1) {
            // If GCD is 1 and size >= 2, a coprime pair exists, thus a good subsequence exists.
            existsGoodSubsequence = true;
        }

        if (existsGoodSubsequence) {
            goodSubsequenceCount++;
        }
    }

    return goodSubsequenceCount;
}

