    let d = 2;
    let temp = n;
    while (d * d <= temp) {
        while (temp % d === 0) {
            factors.set(d, (factors.get(d) || 0) + 1);
            temp /= d;
        }
        d++;
    }
    if (temp > 1) {
        factors.set(temp, (factors.get(temp) || 0) + 1);
